import{i as e,r as t,s as n,t as r}from"./app-B1jqjtqq.js";var i=JSON.parse(`{"path":"/linux-tutor/awesome-shell/02-file-dir.html","title":"文件与目录操作命令","lang":"zh-CN","frontmatter":{"description":"文件与目录操作命令 一、目录导航 pwd — 显示当前工作目录 cd — 切换目录 dirs — 显示目录栈 二、列出目录内容 ls — 列出文件和目录 ls -l 输出格式： 权限说明： 第1位：- 文件, d 目录, l 符号链接, c 字符设备, b 块设备 第2-4位：所有者权限（rwx） 第5-7位：所属组权限（rwx） 第8-10位：其他人...","head":[["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"文件与目录操作命令\\",\\"image\\":[\\"\\"],\\"dateModified\\":\\"2026-07-15T12:37:10.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"yzqdev\\",\\"url\\":\\"http://www.yzqdev.top\\"}]}"],["meta",{"property":"og:url","content":"https://yzqdev.github.io/cs-guide/cs-guide/linux-tutor/awesome-shell/02-file-dir.html"}],["meta",{"property":"og:site_name","content":"cs-guide"}],["meta",{"property":"og:title","content":"文件与目录操作命令"}],["meta",{"property":"og:description","content":"文件与目录操作命令 一、目录导航 pwd — 显示当前工作目录 cd — 切换目录 dirs — 显示目录栈 二、列出目录内容 ls — 列出文件和目录 ls -l 输出格式： 权限说明： 第1位：- 文件, d 目录, l 符号链接, c 字符设备, b 块设备 第2-4位：所有者权限（rwx） 第5-7位：所属组权限（rwx） 第8-10位：其他人..."}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2026-07-15T12:37:10.000Z"}],["meta",{"property":"article:modified_time","content":"2026-07-15T12:37:10.000Z"}]]},"git":{"createdTime":1784119030000,"updatedTime":1784119030000,"contributors":[{"name":"yzqdev","username":"yzqdev","email":"yzqdev@outlook.com","commits":1,"url":"https://github.com/yzqdev"}]},"readingTime":{"minutes":10.1,"words":3029},"filePathRelative":"linux-tutor/awesome-shell/02-file-dir.md","autoDesc":true}`),a={name:`02-file-dir.md`};function o(r,i,a,o,s,c){return n(),t(`div`,null,[...i[0]||=[e(`<h1 id="文件与目录操作命令" tabindex="-1"><a class="header-anchor" href="#文件与目录操作命令"><span>文件与目录操作命令</span></a></h1><h2 id="一、目录导航" tabindex="-1"><a class="header-anchor" href="#一、目录导航"><span>一、目录导航</span></a></h2><h3 id="pwd-—-显示当前工作目录" tabindex="-1"><a class="header-anchor" href="#pwd-—-显示当前工作目录"><span><code>pwd</code> — 显示当前工作目录</span></a></h3><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token builtin class-name">pwd</span>          <span class="token comment"># 显示当前路径：/home/user</span></span>
<span class="line"><span class="token builtin class-name">pwd</span> <span class="token parameter variable">-P</span>       <span class="token comment"># 显示物理路径（忽略符号链接）</span></span>
<span class="line"><span class="token builtin class-name">pwd</span> <span class="token parameter variable">-L</span>       <span class="token comment"># 显示逻辑路径（默认，含符号链接）</span></span>
<span class="line"></span></code></pre></div><h3 id="cd-—-切换目录" tabindex="-1"><a class="header-anchor" href="#cd-—-切换目录"><span><code>cd</code> — 切换目录</span></a></h3><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token builtin class-name">cd</span> /home/user/Documents    <span class="token comment"># 切换到绝对路径</span></span>
<span class="line"><span class="token builtin class-name">cd</span> Documents               <span class="token comment"># 切换到相对路径（当前目录下）</span></span>
<span class="line"><span class="token builtin class-name">cd</span> <span class="token punctuation">..</span>                      <span class="token comment"># 返回上级目录</span></span>
<span class="line"><span class="token builtin class-name">cd</span> <span class="token punctuation">..</span>/<span class="token punctuation">..</span>                   <span class="token comment"># 返回上两级目录</span></span>
<span class="line"><span class="token builtin class-name">cd</span> -                       <span class="token comment"># 返回上一个目录</span></span>
<span class="line"><span class="token builtin class-name">cd</span> ~                       <span class="token comment"># 切换到当前用户家目录</span></span>
<span class="line"><span class="token builtin class-name">cd</span>                         <span class="token comment"># 同 cd ~</span></span>
<span class="line"><span class="token builtin class-name">cd</span> ~user1                  <span class="token comment"># 切换到 user1 的家目录</span></span>
<span class="line"><span class="token builtin class-name">cd</span> /                       <span class="token comment"># 切换到根目录</span></span>
<span class="line"></span></code></pre></div><h3 id="dirs-—-显示目录栈" tabindex="-1"><a class="header-anchor" href="#dirs-—-显示目录栈"><span><code>dirs</code> — 显示目录栈</span></a></h3><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token function">dirs</span>                       <span class="token comment"># 显示目录栈</span></span>
<span class="line"><span class="token function">pushd</span> /tmp                 <span class="token comment"># 将目录推入栈并切换</span></span>
<span class="line"><span class="token function">popd</span>                       <span class="token comment"># 弹出栈顶目录并切换</span></span>
<span class="line"><span class="token function">pushd</span> +1                   <span class="token comment"># 切换到栈中第 1 个目录</span></span>
<span class="line"></span></code></pre></div><hr><h2 id="二、列出目录内容" tabindex="-1"><a class="header-anchor" href="#二、列出目录内容"><span>二、列出目录内容</span></a></h2><h3 id="ls-—-列出文件和目录" tabindex="-1"><a class="header-anchor" href="#ls-—-列出文件和目录"><span><code>ls</code> — 列出文件和目录</span></a></h3><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token function">ls</span>                         <span class="token comment"># 列出当前目录内容（简洁）</span></span>
<span class="line"><span class="token function">ls</span> <span class="token parameter variable">-l</span>                      <span class="token comment"># 长格式显示（权限、大小、修改时间）</span></span>
<span class="line"><span class="token function">ls</span> <span class="token parameter variable">-a</span>                      <span class="token comment"># 显示所有文件（包括隐藏文件）</span></span>
<span class="line"><span class="token function">ls</span> <span class="token parameter variable">-la</span>                     <span class="token comment"># 长格式显示所有文件（最常用）</span></span>
<span class="line"><span class="token function">ls</span> <span class="token parameter variable">-lh</span>                     <span class="token comment"># 以人类可读格式显示大小（K, M, G）</span></span>
<span class="line"><span class="token function">ls</span> <span class="token parameter variable">-lt</span>                     <span class="token comment"># 按修改时间排序（最新在前）</span></span>
<span class="line"><span class="token function">ls</span> <span class="token parameter variable">-ltr</span>                    <span class="token comment"># 按修改时间排序（最旧在前）</span></span>
<span class="line"><span class="token function">ls</span> <span class="token parameter variable">-lS</span>                     <span class="token comment"># 按文件大小排序（最大在前）</span></span>
<span class="line"><span class="token function">ls</span> <span class="token parameter variable">-lSr</span>                    <span class="token comment"># 按文件大小排序（最小在前）</span></span>
<span class="line"><span class="token function">ls</span> <span class="token parameter variable">-R</span>                      <span class="token comment"># 递归显示子目录</span></span>
<span class="line"><span class="token function">ls</span> <span class="token parameter variable">-d</span> */                   <span class="token comment"># 只显示目录</span></span>
<span class="line"><span class="token function">ls</span> <span class="token parameter variable">-1</span>                      <span class="token comment"># 每行显示一个文件</span></span>
<span class="line"><span class="token function">ls</span> <span class="token parameter variable">-F</span>                      <span class="token comment"># 在文件后加类型标记（/ 目录, * 可执行）</span></span>
<span class="line"><span class="token function">ls</span> <span class="token parameter variable">-la</span> <span class="token parameter variable">--color</span><span class="token operator">=</span>auto        <span class="token comment"># 彩色显示（一般默认已启用）</span></span>
<span class="line"></span></code></pre></div><p><strong><code>ls -l</code> 输出格式</strong>：</p><div class="language-text" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">-rw-r--r--  1 user group  1024 Jul 14 10:30 file.txt</span>
<span class="line">^^^^^^^^^  ^ ^^^^^ ^^^^^  ^^^^ ^^^^^^^^^^^ ^^^^^^^^</span>
<span class="line">权限       链接数 所有者 组    大小    修改时间   文件名</span>
<span class="line"></span></code></pre></div><p>权限说明：</p><ul><li>第1位：<code>-</code> 文件, <code>d</code> 目录, <code>l</code> 符号链接, <code>c</code> 字符设备, <code>b</code> 块设备</li><li>第2-4位：所有者权限（rwx）</li><li>第5-7位：所属组权限（rwx）</li><li>第8-10位：其他人权限（rwx）</li></ul><hr><h2 id="三、创建与删除" tabindex="-1"><a class="header-anchor" href="#三、创建与删除"><span>三、创建与删除</span></a></h2><h3 id="mkdir-—-创建目录" tabindex="-1"><a class="header-anchor" href="#mkdir-—-创建目录"><span><code>mkdir</code> — 创建目录</span></a></h3><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token function">mkdir</span> mydir                        <span class="token comment"># 创建单个目录</span></span>
<span class="line"><span class="token function">mkdir</span> <span class="token parameter variable">-p</span> parent/child/grandchild   <span class="token comment"># 递归创建多级目录</span></span>
<span class="line"><span class="token function">mkdir</span> <span class="token parameter variable">-m</span> <span class="token number">755</span> mydir                 <span class="token comment"># 创建目录并设置权限</span></span>
<span class="line"><span class="token function">mkdir</span> dir1 dir2 dir3               <span class="token comment"># 同时创建多个目录</span></span>
<span class="line"><span class="token function">mkdir</span> <span class="token punctuation">{</span><span class="token number">1</span><span class="token punctuation">..</span><span class="token number">5</span><span class="token punctuation">}</span>                       <span class="token comment"># 创建 1 2 3 4 5 五个目录</span></span>
<span class="line"><span class="token function">mkdir</span> <span class="token parameter variable">-v</span> mydir                     <span class="token comment"># 显示创建过程信息</span></span>
<span class="line"></span></code></pre></div><h3 id="touch-—-创建空文件-更新文件时间戳" tabindex="-1"><a class="header-anchor" href="#touch-—-创建空文件-更新文件时间戳"><span><code>touch</code> — 创建空文件 / 更新文件时间戳</span></a></h3><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token function">touch</span> file.txt                      <span class="token comment"># 创建空文件（已存在则更新时间戳）</span></span>
<span class="line"><span class="token function">touch</span> file1.txt file2.txt           <span class="token comment"># 创建多个文件</span></span>
<span class="line"><span class="token function">touch</span> <span class="token parameter variable">-a</span> file.txt                   <span class="token comment"># 只更新访问时间（atime）</span></span>
<span class="line"><span class="token function">touch</span> <span class="token parameter variable">-m</span> file.txt                   <span class="token comment"># 只更新修改时间（mtime）</span></span>
<span class="line"><span class="token function">touch</span> <span class="token parameter variable">-t</span> <span class="token number">202601011200</span> file.txt      <span class="token comment"># 设置指定时间（YYYYMMDDhhmm）</span></span>
<span class="line"><span class="token function">touch</span> <span class="token parameter variable">-r</span> ref.txt target.txt         <span class="token comment"># 以 ref.txt 的时间为准</span></span>
<span class="line"><span class="token function">touch</span> <span class="token punctuation">{</span><span class="token number">1</span><span class="token punctuation">..</span><span class="token number">10</span><span class="token punctuation">}</span>.txt                   <span class="token comment"># 创建 1.txt ~ 10.txt</span></span>
<span class="line"></span></code></pre></div><h3 id="rmdir-—-删除空目录" tabindex="-1"><a class="header-anchor" href="#rmdir-—-删除空目录"><span><code>rmdir</code> — 删除空目录</span></a></h3><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token function">rmdir</span> emptydir                      <span class="token comment"># 删除空目录</span></span>
<span class="line"><span class="token function">rmdir</span> <span class="token parameter variable">-p</span> parent/child               <span class="token comment"># 递归删除空目录（从子到父）</span></span>
<span class="line"></span></code></pre></div><h3 id="rm-—-删除文件或目录" tabindex="-1"><a class="header-anchor" href="#rm-—-删除文件或目录"><span><code>rm</code> — 删除文件或目录</span></a></h3><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token function">rm</span> file.txt                         <span class="token comment"># 删除文件</span></span>
<span class="line"><span class="token function">rm</span> <span class="token parameter variable">-f</span> file.txt                      <span class="token comment"># 强制删除（不提示）</span></span>
<span class="line"><span class="token function">rm</span> <span class="token parameter variable">-i</span> file.txt                      <span class="token comment"># 交互式删除（需要确认）</span></span>
<span class="line"><span class="token function">rm</span> <span class="token parameter variable">-r</span> dir/                          <span class="token comment"># 递归删除目录及其内容</span></span>
<span class="line"><span class="token function">rm</span> <span class="token parameter variable">-rf</span> dir/                         <span class="token comment"># 强制递归删除（⚠️ 危险！）</span></span>
<span class="line"><span class="token function">rm</span> <span class="token parameter variable">-v</span> file.txt                      <span class="token comment"># 显示删除过程</span></span>
<span class="line"><span class="token function">rm</span> *.txt                            <span class="token comment"># 删除所有 .txt 文件</span></span>
<span class="line"><span class="token function">rm</span> <span class="token parameter variable">-rf</span> /path/to/dir/*               <span class="token comment"># 删除目录下所有内容（保留目录本身）</span></span>
<span class="line"></span></code></pre></div><blockquote><p>⚠️ <code>rm -rf</code> 非常危险，建议使用 <code>trash</code> 或 <code>safe-rm</code> 替代。</p></blockquote><hr><h2 id="四、复制、移动与重命名" tabindex="-1"><a class="header-anchor" href="#四、复制、移动与重命名"><span>四、复制、移动与重命名</span></a></h2><h3 id="cp-—-复制文件或目录" tabindex="-1"><a class="header-anchor" href="#cp-—-复制文件或目录"><span><code>cp</code> — 复制文件或目录</span></a></h3><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token function">cp</span> source.txt dest.txt               <span class="token comment"># 复制文件</span></span>
<span class="line"><span class="token function">cp</span> <span class="token parameter variable">-i</span> source.txt dest.txt            <span class="token comment"># 覆盖前提示确认</span></span>
<span class="line"><span class="token function">cp</span> <span class="token parameter variable">-f</span> source.txt dest.txt            <span class="token comment"># 强制覆盖（不提示）</span></span>
<span class="line"><span class="token function">cp</span> <span class="token parameter variable">-n</span> source.txt dest.txt            <span class="token comment"># 不覆盖已存在的文件</span></span>
<span class="line"><span class="token function">cp</span> <span class="token parameter variable">-b</span> source.txt dest.txt            <span class="token comment"># 覆盖前备份（生成 dest.txt~）</span></span>
<span class="line"><span class="token function">cp</span> <span class="token parameter variable">-v</span> source.txt dest.txt            <span class="token comment"># 显示复制过程</span></span>
<span class="line"></span>
<span class="line"><span class="token function">cp</span> file.txt dir/                     <span class="token comment"># 复制到目录（保留原名）</span></span>
<span class="line"><span class="token function">cp</span> <span class="token parameter variable">-r</span> sourcedir/ destdir/            <span class="token comment"># 递归复制目录</span></span>
<span class="line"><span class="token function">cp</span> <span class="token parameter variable">-a</span> sourcedir/ destdir/            <span class="token comment"># 归档复制（保留权限、时间戳、链接等）</span></span>
<span class="line"><span class="token function">cp</span> <span class="token parameter variable">-p</span> source.txt dest.txt            <span class="token comment"># 保留源文件属性（权限、时间）</span></span>
<span class="line"><span class="token function">cp</span> <span class="token parameter variable">-u</span> source.txt dest.txt            <span class="token comment"># 只复制更新的文件（增量复制）</span></span>
<span class="line"><span class="token function">cp</span> <span class="token parameter variable">-l</span> source.txt link.txt            <span class="token comment"># 创建硬链接（而非复制）</span></span>
<span class="line"><span class="token function">cp</span> <span class="token parameter variable">-s</span> source.txt symlink.txt         <span class="token comment"># 创建符号链接（而非复制）</span></span>
<span class="line"></span>
<span class="line"><span class="token function">cp</span> <span class="token parameter variable">-r</span> dir1/ dir2/ dir3/ dest/        <span class="token comment"># 复制多个目录到目标</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="cp-常用组合" tabindex="-1"><a class="header-anchor" href="#cp-常用组合"><span><code>cp</code> 常用组合</span></a></h3><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token function">cp</span> <span class="token parameter variable">-rva</span> sourcedir/ destdir/          <span class="token comment"># 递归 + 详细 + 保留属性</span></span>
<span class="line"><span class="token function">cp</span> <span class="token parameter variable">-rpf</span> sourcedir/ destdir/          <span class="token comment"># 递归 + 保留 + 覆盖不提示</span></span>
<span class="line"></span></code></pre></div><h3 id="mv-—-移动或重命名文件" tabindex="-1"><a class="header-anchor" href="#mv-—-移动或重命名文件"><span><code>mv</code> — 移动或重命名文件</span></a></h3><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token function">mv</span> source.txt dest.txt               <span class="token comment"># 重命名文件</span></span>
<span class="line"><span class="token function">mv</span> file.txt dir/                     <span class="token comment"># 移动文件到目录</span></span>
<span class="line"><span class="token function">mv</span> <span class="token parameter variable">-i</span> source.txt dest.txt            <span class="token comment"># 覆盖前提示</span></span>
<span class="line"><span class="token function">mv</span> <span class="token parameter variable">-f</span> source.txt dest.txt            <span class="token comment"># 强制覆盖</span></span>
<span class="line"><span class="token function">mv</span> <span class="token parameter variable">-n</span> source.txt dest.txt            <span class="token comment"># 不覆盖已存在的</span></span>
<span class="line"><span class="token function">mv</span> <span class="token parameter variable">-v</span> source.txt dest.txt            <span class="token comment"># 显示过程</span></span>
<span class="line"><span class="token function">mv</span> <span class="token parameter variable">-u</span> source.txt dest.txt            <span class="token comment"># 只移动更新的文件</span></span>
<span class="line"></span>
<span class="line"><span class="token function">mv</span> dir1/ dir2/                       <span class="token comment"># 重命名目录</span></span>
<span class="line"><span class="token function">mv</span> *.txt dir/                        <span class="token comment"># 移动所有 txt 文件到目录</span></span>
<span class="line"><span class="token function">mv</span> file1.txt file2.txt dir/          <span class="token comment"># 移动多个文件到目录</span></span>
<span class="line"></span></code></pre></div><h3 id="rename-—-批量重命名" tabindex="-1"><a class="header-anchor" href="#rename-—-批量重命名"><span><code>rename</code> — 批量重命名</span></a></h3><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token comment"># 基本语法：rename &#39;s/原字符串/新字符串/&#39; 文件</span></span>
<span class="line"><span class="token function">rename</span> <span class="token string">&#39;s/\\.htm$/\\.html/&#39;</span> *.htm      <span class="token comment"># 将 .htm 改为 .html</span></span>
<span class="line"><span class="token function">rename</span> <span class="token string">&#39;s/ /_/g&#39;</span> *                   <span class="token comment"># 将文件名中的空格改为下划线</span></span>
<span class="line"><span class="token function">rename</span> <span class="token string">&#39;y/A-Z/a-z/&#39;</span> *                <span class="token comment"># 将文件名改为小写</span></span>
<span class="line"><span class="token function">rename</span> <span class="token string">&#39;s/^/backup_/&#39;</span> *              <span class="token comment"># 在所有文件名前加 backup_</span></span>
<span class="line"><span class="token function">rename</span> <span class="token string">&#39;s/\\([0-9]\\)/第$1集/&#39;</span> *.mp4   <span class="token comment"># 使用正则替换</span></span>
<span class="line"></span></code></pre></div><hr><h2 id="五、查看文件类型与信息" tabindex="-1"><a class="header-anchor" href="#五、查看文件类型与信息"><span>五、查看文件类型与信息</span></a></h2><h3 id="file-—-查看文件类型" tabindex="-1"><a class="header-anchor" href="#file-—-查看文件类型"><span><code>file</code> — 查看文件类型</span></a></h3><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token function">file</span> file.txt                        <span class="token comment"># 查看文件类型</span></span>
<span class="line"><span class="token function">file</span> <span class="token parameter variable">-i</span> file.txt                     <span class="token comment"># 显示 MIME 类型</span></span>
<span class="line"><span class="token function">file</span> *                               <span class="token comment"># 查看当前目录所有文件类型</span></span>
<span class="line"><span class="token function">file</span> <span class="token parameter variable">-b</span> file.txt                     <span class="token comment"># 仅显示类型描述（不显示文件名）</span></span>
<span class="line"><span class="token function">file</span> /usr/bin/ls                     <span class="token comment"># 查看二进制文件类型</span></span>
<span class="line"></span></code></pre></div><h3 id="stat-—-显示文件详细信息" tabindex="-1"><a class="header-anchor" href="#stat-—-显示文件详细信息"><span><code>stat</code> — 显示文件详细信息</span></a></h3><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token function">stat</span> file.txt                        <span class="token comment"># 显示文件的完整元数据</span></span>
<span class="line"><span class="token function">stat</span> <span class="token parameter variable">-c</span> <span class="token string">&#39;%s %y %n&#39;</span> *.txt            <span class="token comment"># 自定义格式：大小 修改时间 文件名</span></span>
<span class="line"><span class="token function">stat</span> <span class="token parameter variable">-f</span> /                           <span class="token comment"># 查看文件系统信息</span></span>
<span class="line"></span></code></pre></div><p><strong>输出示例</strong>：</p><div class="language-text" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">  File: file.txt</span>
<span class="line">  Size: 1024            Blocks: 8          IO Block: 4096   regular file</span>
<span class="line">Device: 801h/2049d      Inode: 1234567     Links: 1</span>
<span class="line">Access: (0644/-rw-r--r--)  Uid: ( 1000/   user)   Gid: ( 1000/   group)</span>
<span class="line">Access: 2026-07-14 10:30:00.000000000 +0800</span>
<span class="line">Modify: 2026-07-14 10:30:00.000000000 +0800</span>
<span class="line">Change: 2026-07-14 10:30:00.000000000 +0800</span>
<span class="line"></span></code></pre></div><h3 id="wc-—-统计文件信息" tabindex="-1"><a class="header-anchor" href="#wc-—-统计文件信息"><span><code>wc</code> — 统计文件信息</span></a></h3><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token function">wc</span> file.txt                          <span class="token comment"># 输出：行数 单词数 字符数 文件名</span></span>
<span class="line"><span class="token function">wc</span> <span class="token parameter variable">-l</span> file.txt                       <span class="token comment"># 只统计行数</span></span>
<span class="line"><span class="token function">wc</span> <span class="token parameter variable">-w</span> file.txt                       <span class="token comment"># 只统计单词数</span></span>
<span class="line"><span class="token function">wc</span> <span class="token parameter variable">-c</span> file.txt                       <span class="token comment"># 只统计字节数</span></span>
<span class="line"><span class="token function">wc</span> <span class="token parameter variable">-m</span> file.txt                       <span class="token comment"># 只统计字符数</span></span>
<span class="line"><span class="token function">wc</span> <span class="token parameter variable">-L</span> file.txt                       <span class="token comment"># 显示最长行的长度</span></span>
<span class="line"><span class="token function">wc</span> *.txt                             <span class="token comment"># 统计所有 txt 文件</span></span>
<span class="line"></span></code></pre></div><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token comment"># 实用技巧</span></span>
<span class="line"><span class="token function">wc</span> <span class="token parameter variable">-l</span> <span class="token operator">&lt;</span> file.txt                     <span class="token comment"># 只输出数字（无文件名）</span></span>
<span class="line"><span class="token function">cat</span> file.txt <span class="token operator">|</span> <span class="token function">wc</span> <span class="token parameter variable">-l</span>                 <span class="token comment"># 管道统计行数</span></span>
<span class="line"><span class="token function">find</span> <span class="token builtin class-name">.</span> <span class="token parameter variable">-name</span> <span class="token string">&#39;*.log&#39;</span> <span class="token operator">|</span> <span class="token function">wc</span> <span class="token parameter variable">-l</span>        <span class="token comment"># 统计 log 文件数量</span></span>
<span class="line"></span></code></pre></div><hr><h2 id="六、链接文件" tabindex="-1"><a class="header-anchor" href="#六、链接文件"><span>六、链接文件</span></a></h2><h3 id="ln-—-创建链接" tabindex="-1"><a class="header-anchor" href="#ln-—-创建链接"><span><code>ln</code> — 创建链接</span></a></h3><p>Linux 链接分为两种：<strong>硬链接</strong>和<strong>符号链接（软链接）</strong>。</p><table><thead><tr><th>特性</th><th>硬链接</th><th>符号链接</th></tr></thead><tbody><tr><td>inode 相同</td><td>✅</td><td>❌</td></tr><tr><td>可跨文件系统</td><td>❌</td><td>✅</td></tr><tr><td>可链接目录</td><td>❌</td><td>✅</td></tr><tr><td>源文件删除后仍可用</td><td>✅</td><td>❌（变成死链接）</td></tr><tr><td>占用独立 inode</td><td>❌（共享）</td><td>✅</td></tr></tbody></table><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token comment"># 硬链接</span></span>
<span class="line"><span class="token function">ln</span> source.txt hardlink.txt           <span class="token comment"># 创建硬链接</span></span>
<span class="line"><span class="token function">ln</span> <span class="token parameter variable">-f</span> source.txt hardlink.txt        <span class="token comment"># 强制创建（覆盖已存在）</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 符号链接（软链接）</span></span>
<span class="line"><span class="token function">ln</span> <span class="token parameter variable">-s</span> source.txt symlink.txt         <span class="token comment"># 创建符号链接</span></span>
<span class="line"><span class="token function">ln</span> <span class="token parameter variable">-sf</span> source.txt symlink.txt        <span class="token comment"># 强制创建/更新符号链接</span></span>
<span class="line"><span class="token function">ln</span> <span class="token parameter variable">-s</span> /usr/local/bin/myapp myapp     <span class="token comment"># 为可执行程序创建链接</span></span>
<span class="line"><span class="token function">ln</span> <span class="token parameter variable">-s</span> <span class="token punctuation">..</span>/lib ./lib                   <span class="token comment"># 相对路径的符号链接</span></span>
<span class="line"><span class="token function">ln</span> <span class="token parameter variable">-snf</span> new_target symlink.txt       <span class="token comment"># 更新符号链接目标</span></span>
<span class="line"></span></code></pre></div><p><strong>查看链接</strong>：</p><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token function">ls</span> <span class="token parameter variable">-l</span>                                 <span class="token comment"># 软链接显示 -&gt; 指向目标</span></span>
<span class="line"><span class="token function">ls</span> <span class="token parameter variable">-la</span> /proc/self/fd/                 <span class="token comment"># 查看当前进程打开的文件描述符</span></span>
<span class="line">readlink symlink.txt                  <span class="token comment"># 显示符号链接指向的目标路径</span></span>
<span class="line">readlink <span class="token parameter variable">-f</span> symlink.txt               <span class="token comment"># 解析所有符号链接得到绝对路径</span></span>
<span class="line"><span class="token function">find</span> / <span class="token parameter variable">-type</span> l                        <span class="token comment"># 查找所有符号链接</span></span>
<span class="line"><span class="token function">find</span> / <span class="token parameter variable">-xtype</span> l                       <span class="token comment"># 查找死链接（指向不存在的文件）</span></span>
<span class="line"></span></code></pre></div><hr><h2 id="七、查找文件" tabindex="-1"><a class="header-anchor" href="#七、查找文件"><span>七、查找文件</span></a></h2><h3 id="find-—-强大灵活的文件搜索" tabindex="-1"><a class="header-anchor" href="#find-—-强大灵活的文件搜索"><span><code>find</code> — 强大灵活的文件搜索</span></a></h3><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token comment"># 按名称查找</span></span>
<span class="line"><span class="token function">find</span> <span class="token builtin class-name">.</span> <span class="token parameter variable">-name</span> <span class="token string">&quot;file.txt&quot;</span>              <span class="token comment"># 当前目录下找 file.txt</span></span>
<span class="line"><span class="token function">find</span> / <span class="token parameter variable">-name</span> <span class="token string">&quot;*.log&quot;</span>                 <span class="token comment"># 全盘找 .log 文件（需 root）</span></span>
<span class="line"><span class="token function">find</span> /home <span class="token parameter variable">-iname</span> <span class="token string">&quot;readme.md&quot;</span>        <span class="token comment"># 忽略大小写</span></span>
<span class="line"><span class="token function">find</span> <span class="token builtin class-name">.</span> <span class="token parameter variable">-name</span> <span class="token string">&quot;[a-z]*.txt&quot;</span>            <span class="token comment"># 使用通配符</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 按类型查找</span></span>
<span class="line"><span class="token function">find</span> <span class="token builtin class-name">.</span> <span class="token parameter variable">-type</span> f                       <span class="token comment"># 只找普通文件</span></span>
<span class="line"><span class="token function">find</span> <span class="token builtin class-name">.</span> <span class="token parameter variable">-type</span> d                       <span class="token comment"># 只找目录</span></span>
<span class="line"><span class="token function">find</span> <span class="token builtin class-name">.</span> <span class="token parameter variable">-type</span> l                       <span class="token comment"># 只找符号链接</span></span>
<span class="line"><span class="token function">find</span> <span class="token builtin class-name">.</span> <span class="token parameter variable">-type</span> f <span class="token parameter variable">-name</span> <span class="token string">&quot;*.sh&quot;</span>          <span class="token comment"># 组合条件</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 按大小查找</span></span>
<span class="line"><span class="token function">find</span> <span class="token builtin class-name">.</span> <span class="token parameter variable">-size</span> +100M                   <span class="token comment"># 大于 100MB 的文件</span></span>
<span class="line"><span class="token function">find</span> <span class="token builtin class-name">.</span> <span class="token parameter variable">-size</span> <span class="token parameter variable">-1k</span>                     <span class="token comment"># 小于 1KB 的文件</span></span>
<span class="line"><span class="token function">find</span> <span class="token builtin class-name">.</span> <span class="token parameter variable">-size</span> 1024k                   <span class="token comment"># 正好 1024KB 的文件</span></span>
<span class="line"><span class="token function">find</span> <span class="token builtin class-name">.</span> <span class="token parameter variable">-size</span> +50M <span class="token parameter variable">-size</span> <span class="token parameter variable">-100M</span>       <span class="token comment"># 50M ~ 100M 之间的文件</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 按时间查找</span></span>
<span class="line"><span class="token function">find</span> <span class="token builtin class-name">.</span> <span class="token parameter variable">-mtime</span> <span class="token parameter variable">-7</span>                     <span class="token comment"># 7天内修改过的文件</span></span>
<span class="line"><span class="token function">find</span> <span class="token builtin class-name">.</span> <span class="token parameter variable">-mtime</span> +30                    <span class="token comment"># 30天前修改过的文件</span></span>
<span class="line"><span class="token function">find</span> <span class="token builtin class-name">.</span> <span class="token parameter variable">-mmin</span> <span class="token parameter variable">-60</span>                     <span class="token comment"># 60分钟内修改过的文件</span></span>
<span class="line"><span class="token function">find</span> <span class="token builtin class-name">.</span> <span class="token parameter variable">-atime</span> <span class="token parameter variable">-1</span>                     <span class="token comment"># 1天内访问过的文件</span></span>
<span class="line"><span class="token function">find</span> <span class="token builtin class-name">.</span> <span class="token parameter variable">-ctime</span> <span class="token parameter variable">-1</span>                     <span class="token comment"># 1天内状态改变过的文件</span></span>
<span class="line"><span class="token function">find</span> <span class="token builtin class-name">.</span> <span class="token parameter variable">-newer</span> ref.txt                <span class="token comment"># 比 ref.txt 更新的文件</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 按权限查找</span></span>
<span class="line"><span class="token function">find</span> <span class="token builtin class-name">.</span> <span class="token parameter variable">-perm</span> <span class="token number">755</span>                     <span class="token comment"># 权限为 755 的文件</span></span>
<span class="line"><span class="token function">find</span> <span class="token builtin class-name">.</span> <span class="token parameter variable">-perm</span> <span class="token parameter variable">-4000</span>                  <span class="token comment"># 设置了 SUID 的文件</span></span>
<span class="line"><span class="token function">find</span> <span class="token builtin class-name">.</span> <span class="token parameter variable">-perm</span> /u<span class="token operator">=</span>r                    <span class="token comment"># 所有者有读权限</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 按所有者查找</span></span>
<span class="line"><span class="token function">find</span> <span class="token builtin class-name">.</span> <span class="token parameter variable">-user</span> root                    <span class="token comment"># root 用户的文件</span></span>
<span class="line"><span class="token function">find</span> <span class="token builtin class-name">.</span> <span class="token parameter variable">-group</span> www-data               <span class="token comment"># www-data 组的文件</span></span>
<span class="line"><span class="token function">find</span> <span class="token builtin class-name">.</span> <span class="token parameter variable">-nouser</span>                       <span class="token comment"># 没有所有者的文件（孤儿文件）</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 执行操作</span></span>
<span class="line"><span class="token function">find</span> <span class="token builtin class-name">.</span> <span class="token parameter variable">-name</span> <span class="token string">&quot;*.tmp&quot;</span> <span class="token parameter variable">-delete</span>                        <span class="token comment"># 找到并删除</span></span>
<span class="line"><span class="token function">find</span> <span class="token builtin class-name">.</span> <span class="token parameter variable">-name</span> <span class="token string">&quot;*.bak&quot;</span> <span class="token parameter variable">-exec</span> <span class="token function">rm</span> <span class="token punctuation">{</span><span class="token punctuation">}</span> <span class="token punctuation">\\</span><span class="token punctuation">;</span>                 <span class="token comment"># 找到并执行命令</span></span>
<span class="line"><span class="token function">find</span> <span class="token builtin class-name">.</span> <span class="token parameter variable">-name</span> <span class="token string">&quot;*.log&quot;</span> <span class="token parameter variable">-exec</span> <span class="token function">rm</span> <span class="token parameter variable">-f</span> <span class="token punctuation">{</span><span class="token punctuation">}</span> +               <span class="token comment"># + 表示合并参数（效率更高）</span></span>
<span class="line"><span class="token function">find</span> <span class="token builtin class-name">.</span> <span class="token parameter variable">-type</span> f <span class="token parameter variable">-exec</span> <span class="token function">chmod</span> <span class="token number">644</span> <span class="token punctuation">{</span><span class="token punctuation">}</span> +                 <span class="token comment"># 批量改权限</span></span>
<span class="line"><span class="token function">find</span> <span class="token builtin class-name">.</span> <span class="token parameter variable">-name</span> <span class="token string">&quot;*.txt&quot;</span> <span class="token parameter variable">-exec</span> <span class="token function">cp</span> <span class="token punctuation">{</span><span class="token punctuation">}</span> /backup/ <span class="token punctuation">\\</span><span class="token punctuation">;</span>        <span class="token comment"># 批量复制</span></span>
<span class="line"><span class="token function">find</span> <span class="token builtin class-name">.</span> <span class="token parameter variable">-type</span> d <span class="token parameter variable">-exec</span> <span class="token function">chmod</span> <span class="token number">755</span> <span class="token punctuation">{</span><span class="token punctuation">}</span> +                 <span class="token comment"># 批量改目录权限</span></span>
<span class="line"><span class="token function">find</span> <span class="token builtin class-name">.</span> <span class="token parameter variable">-name</span> <span class="token string">&quot;*.sh&quot;</span> <span class="token parameter variable">-exec</span> <span class="token function">chmod</span> +x <span class="token punctuation">{</span><span class="token punctuation">}</span> <span class="token punctuation">\\</span><span class="token punctuation">;</span>            <span class="token comment"># 批量加可执行权限</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 高级用法</span></span>
<span class="line"><span class="token function">find</span> <span class="token builtin class-name">.</span> <span class="token parameter variable">-maxdepth</span> <span class="token number">1</span> <span class="token parameter variable">-name</span> <span class="token string">&quot;*.txt&quot;</span>                    <span class="token comment"># 只在当前目录查找（不递归）</span></span>
<span class="line"><span class="token function">find</span> <span class="token builtin class-name">.</span> <span class="token parameter variable">-maxdepth</span> <span class="token number">3</span> <span class="token parameter variable">-name</span> <span class="token string">&quot;*.txt&quot;</span>                    <span class="token comment"># 最多递归 3 层</span></span>
<span class="line"><span class="token function">find</span> <span class="token builtin class-name">.</span> <span class="token parameter variable">-mindepth</span> <span class="token number">2</span> <span class="token parameter variable">-name</span> <span class="token string">&quot;*.txt&quot;</span>                    <span class="token comment"># 从第 2 层开始查</span></span>
<span class="line"><span class="token function">find</span> <span class="token builtin class-name">.</span> <span class="token parameter variable">-empty</span>                                       <span class="token comment"># 查找空文件或空目录</span></span>
<span class="line"><span class="token function">find</span> <span class="token builtin class-name">.</span> <span class="token parameter variable">-maxdepth</span> <span class="token number">1</span> <span class="token parameter variable">-type</span> f <span class="token operator">|</span> <span class="token function">wc</span> <span class="token parameter variable">-l</span>                 <span class="token comment"># 统计文件数量</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="locate-—-快速查找文件-基于数据库" tabindex="-1"><a class="header-anchor" href="#locate-—-快速查找文件-基于数据库"><span><code>locate</code> — 快速查找文件（基于数据库）</span></a></h3><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token function">locate</span> file.txt                      <span class="token comment"># 快速查找（比 find 快，但不实时）</span></span>
<span class="line"><span class="token function">locate</span> <span class="token parameter variable">-i</span> readme                     <span class="token comment"># 忽略大小写</span></span>
<span class="line"><span class="token function">locate</span> <span class="token parameter variable">-c</span> <span class="token string">&quot;*.html&quot;</span>                   <span class="token comment"># 只统计数量</span></span>
<span class="line"><span class="token function">locate</span> <span class="token parameter variable">-r</span> <span class="token string">&#39;\\.txt$&#39;</span>                   <span class="token comment"># 使用正则</span></span>
<span class="line"><span class="token function">locate</span> <span class="token parameter variable">-n</span> <span class="token number">10</span> <span class="token string">&quot;*.conf&quot;</span>                <span class="token comment"># 只显示前 10 条结果</span></span>
<span class="line"></span>
<span class="line"><span class="token function">sudo</span> updatedb                        <span class="token comment"># 更新 locate 数据库（新文件才会被找到）</span></span>
<span class="line"></span></code></pre></div><h3 id="which-—-查找可执行文件的路径" tabindex="-1"><a class="header-anchor" href="#which-—-查找可执行文件的路径"><span><code>which</code> — 查找可执行文件的路径</span></a></h3><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token function">which</span> <span class="token function">ls</span>                             <span class="token comment"># 输出: /usr/bin/ls</span></span>
<span class="line"><span class="token function">which</span> <span class="token parameter variable">-a</span> python                      <span class="token comment"># 显示所有匹配路径</span></span>
<span class="line"><span class="token function">which</span> <span class="token parameter variable">-p</span> <span class="token function">ls</span>                          <span class="token comment"># 输出不带别名解析的路径</span></span>
<span class="line"></span></code></pre></div><h3 id="whereis-—-查找命令的二进制、源码和手册" tabindex="-1"><a class="header-anchor" href="#whereis-—-查找命令的二进制、源码和手册"><span><code>whereis</code> — 查找命令的二进制、源码和手册</span></a></h3><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token function">whereis</span> <span class="token function">ls</span>                           <span class="token comment"># 输出: ls: /usr/bin/ls /usr/share/man/man1/ls.1.gz</span></span>
<span class="line"><span class="token function">whereis</span> <span class="token parameter variable">-b</span> <span class="token function">ls</span>                        <span class="token comment"># 只查找二进制</span></span>
<span class="line"><span class="token function">whereis</span> <span class="token parameter variable">-m</span> <span class="token function">ls</span>                        <span class="token comment"># 只查找手册</span></span>
<span class="line"><span class="token function">whereis</span> <span class="token parameter variable">-s</span> <span class="token function">ls</span>                        <span class="token comment"># 只查找源码</span></span>
<span class="line"></span></code></pre></div><hr><h2 id="八、文件内容截取" tabindex="-1"><a class="header-anchor" href="#八、文件内容截取"><span>八、文件内容截取</span></a></h2><h3 id="head-—-查看文件开头" tabindex="-1"><a class="header-anchor" href="#head-—-查看文件开头"><span><code>head</code> — 查看文件开头</span></a></h3><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token function">head</span> file.txt                        <span class="token comment"># 显示前 10 行</span></span>
<span class="line"><span class="token function">head</span> <span class="token parameter variable">-n</span> <span class="token number">20</span> file.txt                  <span class="token comment"># 显示前 20 行</span></span>
<span class="line"><span class="token function">head</span> <span class="token parameter variable">-20</span> file.txt                    <span class="token comment"># 同上（简写）</span></span>
<span class="line"><span class="token function">head</span> <span class="token parameter variable">-c</span> <span class="token number">100</span> file.txt                 <span class="token comment"># 显示前 100 个字节</span></span>
<span class="line"><span class="token function">head</span> <span class="token parameter variable">-n</span> <span class="token parameter variable">-5</span> file.txt                  <span class="token comment"># 显示除了最后 5 行以外的所有内容（Linux 特有）</span></span>
<span class="line"><span class="token function">head</span> <span class="token parameter variable">-q</span> file1.txt file2.txt          <span class="token comment"># 不显示文件名头</span></span>
<span class="line"><span class="token function">head</span> <span class="token parameter variable">-v</span> file.txt                     <span class="token comment"># 总是显示文件名头</span></span>
<span class="line"></span></code></pre></div><h3 id="tail-—-查看文件末尾" tabindex="-1"><a class="header-anchor" href="#tail-—-查看文件末尾"><span><code>tail</code> — 查看文件末尾</span></a></h3><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token function">tail</span> file.txt                        <span class="token comment"># 显示最后 10 行</span></span>
<span class="line"><span class="token function">tail</span> <span class="token parameter variable">-n</span> <span class="token number">20</span> file.txt                  <span class="token comment"># 显示最后 20 行</span></span>
<span class="line"><span class="token function">tail</span> <span class="token parameter variable">-20</span> file.txt                    <span class="token comment"># 同上（简写）</span></span>
<span class="line"><span class="token function">tail</span> <span class="token parameter variable">-f</span> file.txt                     <span class="token comment"># 实时跟踪文件新增内容（最常用）</span></span>
<span class="line"><span class="token function">tail</span> <span class="token parameter variable">-F</span> file.txt                     <span class="token comment"># 跟踪文件（即使文件被轮转）</span></span>
<span class="line"><span class="token function">tail</span> <span class="token parameter variable">-n</span> +10 file.txt                 <span class="token comment"># 从第 10 行开始显示到末尾</span></span>
<span class="line"><span class="token function">tail</span> <span class="token parameter variable">-c</span> <span class="token number">100</span> file.txt                 <span class="token comment"># 显示最后 100 个字节</span></span>
<span class="line"><span class="token function">tail</span> <span class="token parameter variable">-f</span> <span class="token parameter variable">-n</span> <span class="token number">50</span> file.txt               <span class="token comment"># 从最后 50 行开始实时跟踪</span></span>
<span class="line"><span class="token function">tail</span> <span class="token parameter variable">-q</span> file1.txt file2.txt          <span class="token comment"># 不显示文件名头</span></span>
<span class="line"><span class="token function">tail</span> <span class="token parameter variable">-f</span> access.log <span class="token operator">|</span> <span class="token function">grep</span> <span class="token number">502</span>        <span class="token comment"># 实时跟踪日志并过滤（实用！）</span></span>
<span class="line"></span></code></pre></div><h3 id="less-—-分页查看文件-推荐" tabindex="-1"><a class="header-anchor" href="#less-—-分页查看文件-推荐"><span><code>less</code> — 分页查看文件（推荐）</span></a></h3><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token function">less</span> file.txt                        <span class="token comment"># 打开文件查看</span></span>
<span class="line"><span class="token function">less</span> +G file.txt                     <span class="token comment"># 从文件末尾开始查看</span></span>
<span class="line"><span class="token function">less</span> +/error file.txt                <span class="token comment"># 打开并搜索关键字 &quot;error&quot;</span></span>
<span class="line"><span class="token function">less</span> <span class="token parameter variable">-N</span> file.txt                     <span class="token comment"># 显示行号</span></span>
<span class="line"><span class="token function">less</span> <span class="token parameter variable">-S</span> file.txt                     <span class="token comment"># 不换行（水平滚动）</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># 常用操作（在 less 中）</span></span>
<span class="line"><span class="token comment"># 空格/PageDown  下一页</span></span>
<span class="line"><span class="token comment"># b/PageUp       上一页</span></span>
<span class="line"><span class="token comment"># g              跳到第一行</span></span>
<span class="line"><span class="token comment"># G              跳到最后一行</span></span>
<span class="line"><span class="token comment"># /pattern       向下搜索</span></span>
<span class="line"><span class="token comment"># ?pattern       向上搜索</span></span>
<span class="line"><span class="token comment"># n              下一个匹配</span></span>
<span class="line"><span class="token comment"># N              上一个匹配</span></span>
<span class="line"><span class="token comment"># q              退出</span></span>
<span class="line"><span class="token comment"># h              显示帮助</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="more-—-分页查看-较老" tabindex="-1"><a class="header-anchor" href="#more-—-分页查看-较老"><span><code>more</code> — 分页查看（较老）</span></a></h3><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token function">more</span> file.txt                        <span class="token comment"># 基本分页查看</span></span>
<span class="line"><span class="token function">more</span> <span class="token parameter variable">-d</span> file.txt                     <span class="token comment"># 显示提示（Press space to continue）</span></span>
<span class="line"><span class="token function">more</span> <span class="token parameter variable">-10</span> file.txt                    <span class="token comment"># 每屏显示 10 行</span></span>
<span class="line"><span class="token function">more</span> +100 file.txt                   <span class="token comment"># 从第 100 行开始</span></span>
<span class="line"><span class="token function">more</span> <span class="token parameter variable">-s</span> file.txt                     <span class="token comment"># 压缩多行空行为一行</span></span>
<span class="line"></span></code></pre></div><h3 id="cat-—-查看和拼接文件" tabindex="-1"><a class="header-anchor" href="#cat-—-查看和拼接文件"><span><code>cat</code> — 查看和拼接文件</span></a></h3><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token function">cat</span> file.txt                         <span class="token comment"># 查看文件内容</span></span>
<span class="line"><span class="token function">cat</span> <span class="token parameter variable">-n</span> file.txt                      <span class="token comment"># 显示行号</span></span>
<span class="line"><span class="token function">cat</span> <span class="token parameter variable">-b</span> file.txt                      <span class="token comment"># 显示行号（只对非空行编号）</span></span>
<span class="line"><span class="token function">cat</span> <span class="token parameter variable">-s</span> file.txt                      <span class="token comment"># 压缩连续空行为一行</span></span>
<span class="line"><span class="token function">cat</span> <span class="token parameter variable">-E</span> file.txt                      <span class="token comment"># 在每行末尾显示 $ 符号</span></span>
<span class="line"><span class="token function">cat</span> <span class="token parameter variable">-T</span> file.txt                      <span class="token comment"># 将 Tab 显示为 ^I</span></span>
<span class="line"><span class="token function">cat</span> <span class="token parameter variable">-A</span> file.txt                      <span class="token comment"># 显示所有不可见字符（-vET 的简写）</span></span>
<span class="line"></span>
<span class="line"><span class="token function">cat</span> file1.txt file2.txt              <span class="token comment"># 拼接多个文件</span></span>
<span class="line"><span class="token function">cat</span> file1.txt file2.txt <span class="token operator">&gt;</span> merged.txt <span class="token comment"># 合并到新文件</span></span>
<span class="line"><span class="token function">cat</span> <span class="token operator">&gt;</span> newfile.txt                    <span class="token comment"># 从键盘输入创建文件（Ctrl+D 结束）</span></span>
<span class="line"><span class="token function">cat</span> <span class="token operator">&lt;&lt;</span> <span class="token string">EOF<span class="token bash punctuation"> <span class="token operator">&gt;</span> file.txt                <span class="token comment"># 使用 heredoc 创建文件</span></span></span>
<span class="line">Hello World</span>
<span class="line">EOF</span></span>
<span class="line"></span></code></pre></div><h3 id="tac-—-反向查看文件" tabindex="-1"><a class="header-anchor" href="#tac-—-反向查看文件"><span><code>tac</code> — 反向查看文件</span></a></h3><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token function">tac</span> file.txt                         <span class="token comment"># 从最后一行开始反向显示</span></span>
<span class="line"><span class="token function">tac</span> <span class="token parameter variable">-r</span> <span class="token parameter variable">-s</span> <span class="token string">&#39;.\\|&#39;</span> file.txt             <span class="token comment"># 使用正则作为分隔符</span></span>
<span class="line"></span></code></pre></div><h3 id="rev-—-反转每一行字符" tabindex="-1"><a class="header-anchor" href="#rev-—-反转每一行字符"><span><code>rev</code> — 反转每一行字符</span></a></h3><div class="language-bash" data-highlighter="prismjs" data-ext="sh"><pre><code class="language-bash"><span class="line"><span class="token function">rev</span> file.txt                         <span class="token comment"># 每行字符反转</span></span>
<span class="line"></span></code></pre></div>`,82)]])}var s=r(a,[[`render`,o]]);export{i as _pageData,s as default};